body:
---


Author Name: **Ashutosh Das**
Original Redmine Issue: 219 from https://www.veripool.org
Original Date: 2010-02-26


---

There seems to be an issue with the clock gating signal that
prevents propagation of the signal through the flip-flops.

Bug Description
------------------
Case 1: Setting clock_enable switch on the gclk_vld signal

Issue:  The flop_en_vld does not propagate through the latch
         for enabling the gated clock signal gclk_vld[0]

Case 2: Setting (or not setting) clock_enable switch on the
         flop_en_vld and/or ff_en_vld signals

Issue:  The gated clock gclk_vld[0] toggles but dvld[0]
         input to the flop does not propagate to the output
         signal entry_vld[0]


Here is the SystemC Code (gclk_tb_top.cpp)
===========================================

#include "verilated_vcd_sc.h"
#include "Vgclk_top.h"


int sc_main(int argc, char **argv) {
  sc_clock clk ("clk",10, 0.5, 3, true);
  sc_signal<bool> reset_l;

  Vgclk_top* dut_top;

     dut_top = new Vgclk_top("dut_top"); // SP_CELL (top, Vgclk_top);
     dut_top->clk(clk); // SP_PIN (top, clk, clk);

     Verilated::traceEverOn(true);

     reset_l = 1;
     cout << ("Test beginning...\n");
     sc_start (1, SC_NS);

     VerilatedVcdSc* gclk_tfp = new VerilatedVcdSc;
     dut_top->trace (gclk_tfp, 99);
     gclk_tfp->open ("gclk_dump.vcd");

     while (VL_TIME_Q() < 200) {
       	gclk_tfp->dump(VL_TIME_Q());
	if (VL_TIME_Q() == 10) {
	  cout <<("De-Asserting reset...\n");
	  reset_l = 1;	// Deassert reset
	} else if (VL_TIME_Q() == 2) {
	  cout <<("Asserting reset...\n");
	  reset_l = 0;	// Assert reset
	}
	sc_start(1,SC_NS); // Advance time in ns
     }

     gclk_tfp->close();

     cout <<("Test ending...\n");
     exit(0);
}



Here is the Verilog code with issue (gclk_top.v)
=================================================

// Lib cells
/* verilator lint_off COMBDLY */

module llq (clk, d, q);
     parameter WD = 8;
     input clk;
     input [WD-1:0] d;
     output [WD-1:0] q; 

     reg [WD-1:0] qin;

     always @(clk or d)
         if (clk == 1'b0)
           qin <= d;
           

     assign q = qin;
endmodule

module ffq (clk, d, q);
     parameter WD = 8;
     input clk;
     input [WD-1:0] d;
     output [WD-1:0] q; 

     reg [WD-1:0] qin;

     always @(posedge clk)
         qin <= d;

     assign q = qin;
endmodule
 
/* verilator lint_on COMBDLY */



// ------------------
// Main test module
// ------------------

module gclk_top (clk);
input clk;

wire [127:0] dvld ;
wire [127:0] entry_vld ;

// -------------------------------------------------------
// Clock gating wires with verilator clock_enable syntax
// -------------------------------------------------------

// Case 1: Set clock_enable switch on gclk_vld signal
//  wire [127:0] gclk_vld  /* verilator clock_enable */ ;
//  wire [127:0] ff_en_vld  ;
//  wire [127:0] flop_en_vld ;

// Case 2: Set clock_enable switch on ff_en_vld and flop_en_vld signals
wire [127:0] gclk_vld  ;
wire [127:0] ff_en_vld  /* verilator clock_enable */ ;
wire [127:0] flop_en_vld /* verilator clock_enable */ ;

// clock gating signal control to reproduce the issue
reg [7:0] cnt, dly;
assign    dvld = ({127'b0, ((dly == 5) ? 1'b1 : 1'b0) } << cnt) ;
assign    flop_en_vld = ({127'b0, ((dly == 5) ? 1'b1 : 1'b0) } << cnt) ;

// clock gating
assign gclk_vld = {128{clk}} & ff_en_vld ;

// latch for avoiding glitch on the clock gating control
llq  #(128)  dp_ff_en_vld (.clk(clk), .d(flop_en_vld), .q(ff_en_vld)) ;

// flop that uses the gated clock signal
ffq  #(1)    ff_entry_dvld_0 (.clk(gclk_vld[0]), .d(dvld[0]), .q(entry_vld[0])) ;

// misc control to reproduce the issue
initial begin
  dly = 0;
  cnt = 0;
end

always @ (posedge clk) begin
  if (dly < 5) dly = dly + 1;
  else cnt = cnt + 1;
end

endmodule
